const items = $input.all();
const messages = [];

const templates = {
  pending: '⏳ Olá *{{recipient_name}}*! Seu pedido *{{tracking_code}}* foi recebido e está aguardando coleta.',
  collected: '📦 Seu pedido *{{tracking_code}}* foi coletado e está a caminho do nosso centro de distribuição.',
  in_transit: '🚛 *{{tracking_code}}* está em trânsito! Previsão de entrega: *{{estimated_date}}*.',
  out_for_delivery: '🚀 Ótimas notícias! Seu pedido *{{tracking_code}}* saiu para entrega hoje! Fique em casa!',
  delivered: '✅ Pedido *{{tracking_code}}* entregue com sucesso! Obrigado por confiar na NexCargo.',
  failed: '⚠️ Não conseguimos entregar seu pedido *{{tracking_code}}* hoje. Tentaremos novamente em breve.',
  returned: '↩️ Seu pedido *{{tracking_code}}* foi devolvido ao remetente. Entre em contato conosco.'
};

for (const item of items) {
  const data = item.json;
  const template = templates[data.trigger] || templates[data.status];
  if (!template) continue;

  const message = template
    .replace('{{recipient_name}}', data.recipient_name)
    .replace('{{tracking_code}}', data.tracking_code)
    .replace('{{estimated_date}}', data.estimated_delivery_date || 'em breve');

  messages.push({
    json: {
      notification_id: data.id,
      phone: data.recipient_phone,
      message,
      tracking_code: data.tracking_code
    }
  });
}

return messages;
